import { getAIReply } from "@/utils/ai";

export const maxDuration = 30;

export async function POST(req: Request) {
  try {
    const { rawText, title, location } = await req.json();
    if (!rawText || typeof rawText !== "string" || rawText.trim().length < 5) {
      return Response.json({ error: "Add a few requirements first." }, { status: 400 });
    }

    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) {
      return Response.json({ error: "You must be logged in." }, { status: 401 });
    }

    let groqKey: string | null | undefined = process.env.GROQ_API_KEY;
    let geminiKey: string | null | undefined = process.env.GEMINI_API_KEY;

    const { data: profile } = await supabase
      .from("profiles")
      .select("use_own_keys, groq_api_key, gemini_api_key")
      .eq("id", user.id)
      .single();
    if (profile?.use_own_keys) {
      if (profile.groq_api_key) groqKey = profile.groq_api_key;
      if (profile.gemini_api_key) geminiKey = profile.gemini_api_key;
    }

    const systemPrompt = `You turn a recruiter's freeform requirement notes into a clean list of atomic hiring requirements. Respond with ONLY a JSON object, no markdown fences, no commentary, in exactly this shape:
{"requirements":["short requirement","short requirement"],"description":"a 2-3 sentence candidate-facing summary in plain prose"}

Rules: split long statements into separate, simple requirements, remove duplicates and vague filler, keep each item short (under 12 words), and preserve the employer's intent. If the recruiter mentions a location or remote preference, keep that as a requirement. If title or location are provided, use them to make the summary more natural. If something genuinely is not present, use an empty array or empty string rather than inventing details.`;

    const { text } = await getAIReply({
      groqKey,
      geminiKey,
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: `${title ? `Role: ${title}` : ""}
${location ? `Location: ${location}` : ""}

${rawText.slice(0, 6000)}` },
      ],
      maxTokens: 600,
    });

    const cleaned = text.replace(/```json|```/g, "").trim();
    const parsed = JSON.parse(cleaned);

    return Response.json(parsed);
  } catch (error: any) {
    console.error("🔥 JOB BUILDER FAILED:", error.message || error);
    return Response.json({ error: "Couldn't process that just now. Please try again or fill it in manually." }, { status: 500 });
  }
}
